import React, { useState, useEffect, useRef } from "react";
import axios from "axios";
import Cookies from "js-cookie";
import { useNavigate } from "react-router-dom";
import { Modal } from "bootstrap";
import { toast } from "react-toastify";
import Toast from "../components/Toast";
import dayjs from "dayjs";
import copy from "copy-to-clipboard";

const API_BASE_URL =
  process.env.REACT_APP_API_BASE_URL || "http://localhost:5000/api";

function SupportManagement() {
  const [supports, setSupports] = useState([]);
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();

  const [expandedGroups, setExpandedGroups] = useState({});

  const [filters, setFilters] = useState({
    search: "",
    status: "",
    date: "",
  });

  const [currentPage, setCurrentPage] = useState(1);
  const groupsPerPage = 5;

  const [formData, setFormData] = useState({
    id: null,
    description: "",
    status: "Open",
    reqId: null,
    relatedUserId: null,
  });

  const editModalRef = useRef(null);
  const addModalRef = useRef(null);

  /* ================= FETCH ================= */
  function fetchSupports() {
    setLoading(true);
    const token = Cookies.get("adminToken");

    axios
      .get(API_BASE_URL + "/supports", {
        headers: { Authorization: "Bearer " + token },
      })
      .then((res) => {
        if (res.data.success) {
          setSupports(res.data.data || []);
        } else {
          toast.error("Failed to fetch supports");
        }
      })
      .catch(() => toast.error("Error fetching supports"))
      .finally(() => setLoading(false));
  }

  useEffect(() => {
    const token = Cookies.get("adminToken");
    if (!token) navigate("/");
    else fetchSupports();
  }, [navigate]);

  /* ================= GROUPING ================= */
  const groupedSupports = (() => {
    const mainMap = {};
    const groups = [];

    supports.forEach((item) => {
      if (item.reqType === "Main") {
        mainMap[item.id] = { main: item, followups: [] };
        groups.push(mainMap[item.id]);
      }
    });

    supports.forEach((item) => {
      if (item.reqType === "Followup" && mainMap[item.reqId]) {
        mainMap[item.reqId].followups.push(item);
      }
    });

    groups.forEach((g) =>
      g.followups.sort(
        (a, b) => new Date(a.createdAt) - new Date(b.createdAt),
      ),
    );

    return groups;
  })();

  function toggleGroup(id) {
    setExpandedGroups((prev) => ({
      ...prev,
      [id]: !prev[id],
    }));
  }

  /* ================= FILTER ================= */
  function getLatestStatus(group) {
    if (group.followups.length > 0) {
      return group.followups[group.followups.length - 1].status;
    }
    return group.main.status;
  }

  const filteredGroups = groupedSupports.filter((group) => {
    const searchLower = filters.search.toLowerCase();
    const combinedText =
      (group.main.userFullName || "") +
      (group.main.userPhone || "") +
      (group.main.userEmail || "");

    const searchMatch = filters.search
      ? combinedText.toLowerCase().includes(searchLower)
      : true;

    const statusMatch = filters.status
      ? getLatestStatus(group) === filters.status
      : true;

    const dateMatch = filters.date
      ? dayjs(group.main.createdAt).format("YYYY-MM-DD") === filters.date
      : true;

    return searchMatch && statusMatch && dateMatch;
  });

  useEffect(() => {
    setCurrentPage(1);
  }, [filters]);

  /* ================= PAGINATION ================= */
  const indexOfLast = currentPage * groupsPerPage;
  const indexOfFirst = indexOfLast - groupsPerPage;
  const currentGroups = filteredGroups.slice(indexOfFirst, indexOfLast);
  const totalPages = Math.max(
    Math.ceil(filteredGroups.length / groupsPerPage),
    1,
  );

  function goToNextPage() {
    if (currentPage < totalPages) setCurrentPage((prev) => prev + 1);
  }

  function goToPreviousPage() {
    if (currentPage > 1) setCurrentPage((prev) => prev - 1);
  }

  /* ================= STATUS COLOR ================= */
  function getStatusColor(status) {
    if (!status) return "#ffc107";
    const s = status.toLowerCase();
    if (s === "closed") return "green";
    if (s === "in progress") return "#0dcaf0";
    return "#ffc107";
  }

  /* ================= UI ================= */
  return (
    <div className="container mt-3">
      <Toast />

      <div className="card border-0 mb-3">
        {loading ? (
          <div className="text-center p-3">Loading...</div>
        ) : (
          <div className="table-responsive rounded">
            <table className="table table-striped small mb-0">
              <thead className="table-dark">
                <tr>
                  <th>ID</th>
                  <th>User Name</th>
                  <th>Conversation</th>
                  <th>Status</th>
                  <th>Action</th>
                </tr>
              </thead>
              <tbody>
                {currentGroups.map((group) => (
                  <tr key={group.main.id}>
                    <td>{group.main.id}</td>

                    <td>
                      {group.main.userPrefix} {group.main.userFullName}
                    </td>

                    {/* ================= CONVERSATION COLUMN ================= */}
                    <td style={{ minWidth: "450px" }}>
                      {/* MAIN */}
                      <div className="p-2 mb-2 bg-light border rounded">
                        <div className="d-flex justify-content-between align-items-center">
                          <strong>Main Request</strong>

                          {group.followups.length > 0 && (
                            <button
                              className="btn btn-sm btn-outline-secondary"
                              onClick={() => toggleGroup(group.main.id)}
                            >
                              {expandedGroups[group.main.id]
                                ? "Hide"
                                : "Show"}{" "}
                              Followups ({group.followups.length})
                            </button>
                          )}
                        </div>

                        <div className="mt-2">
                          {group.main.description}
                        </div>

                        <small className="text-muted">
                          {dayjs(group.main.createdAt).format(
                            "DD MMM YYYY hh:mm A",
                          )}
                        </small>
                      </div>

                      {/* FOLLOWUP TIMELINE */}
                      {expandedGroups[group.main.id] && (
                        <div
                          style={{
                            borderLeft: "2px solid #dee2e6",
                            paddingLeft: "20px",
                            marginTop: "15px",
                          }}
                        >
                          {group.followups.map((f) => (
                            <div
                              key={f.id}
                              style={{
                                position: "relative",
                                marginBottom: "20px",
                              }}
                            >
                              {/* DOT */}
                              <div
                                style={{
                                  position: "absolute",
                                  left: "-11px",
                                  top: "5px",
                                  width: "14px",
                                  height: "14px",
                                  borderRadius: "50%",
                                  backgroundColor: getStatusColor(f.status),
                                }}
                              ></div>

                              {/* CARD */}
                              <div className="border rounded p-2 bg-white">
                                <div className="d-flex justify-content-between">
                                  <strong>Followup</strong>
                                </div>

                                <div>{f.description}</div>

                                <small className="text-muted">
                                  {dayjs(f.updatedAt).format(
                                    "DD MMM YYYY hh:mm A",
                                  )}
                                </small>
                              </div>
                            </div>
                          ))}
                        </div>
                      )}
                    </td>

                    {/* STATUS */}
                    <td>
                      <span
                        className="badge"
                        style={{
                          backgroundColor: getStatusColor(
                            getLatestStatus(group),
                          ),
                          color:
                            getLatestStatus(group)?.toLowerCase() === "open"
                              ? "black"
                              : "white",
                        }}
                      >
                        {getLatestStatus(group)}
                      </span>
                    </td>

                    {/* ACTION */}
                    <td>
                      <i
                        className="fa-solid fa-pen-to-square text-primary"
                        style={{ cursor: "pointer" }}
                        title="Add Followup"
                      ></i>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>

      {/* Pagination */}
      <div className="d-flex justify-content-between mb-3">
        <div>
          Page {currentPage} of {totalPages}
        </div>
        <div>
          <button
            className="btn btn-sm border-0"
            disabled={currentPage === 1}
            onClick={goToPreviousPage}
          >
            ◀
          </button>
          <button
            className="btn btn-sm border-0"
            disabled={currentPage === totalPages}
            onClick={goToNextPage}
          >
            ▶
          </button>
        </div>
      </div>
    </div>
  );
}

export default SupportManagement;
